//! Lifecycle action functions for the supervisor state machine.
//!
//! These take the concrete event type `&SupervisorEvent<R>` directly. The
//! `SupervisorEvent` enum is generated by the codegen from the `[event]`
//! section in `blox.toml`.

use bloxide_core::{
    accessor::HasSelfId, lifecycle::ChildLifecycleEvent, messaging::Envelope,
    transition::ActionResult,
};
use bloxide_supervisor_context::{HasChildGroup, HasChildGroupMut, HasPending, SupervisorControl};

use crate::{SupervisorCtx, SupervisorEvent};

/// Start all children in the group.
pub fn start_children<R, C>(ctx: &mut C)
where
    R: bloxide_core::capability::BloxRuntime,
    C: HasSelfId + HasChildGroup<R>,
{
    ctx.children().start_all(ctx.self_id());
}

/// Stop all children in the group.
pub fn stop_all_children<R, C>(ctx: &mut C)
where
    R: bloxide_core::capability::BloxRuntime,
    C: HasSelfId + HasChildGroup<R>,
{
    ctx.children().stop_all(ctx.self_id());
}

/// Handle a Done or Failed child lifecycle event.
pub fn handle_done_or_failed<R>(ctx: &mut SupervisorCtx<R>, ev: &SupervisorEvent<R>) -> ActionResult
where
    R: bloxide_core::capability::BloxRuntime,
{
    if let SupervisorEvent::Child(Envelope(_, ChildLifecycleEvent::Done { child_id }))
    | SupervisorEvent::Child(Envelope(_, ChildLifecycleEvent::Failed { child_id })) = ev
    {
        let from = ctx.self_id();
        let action = ctx.children_mut().handle_done_or_failed(*child_id, from);
        ctx.set_pending(action);
    }
    ActionResult::Ok
}

/// Handle a Reset child lifecycle event.
pub fn handle_reset<R>(ctx: &mut SupervisorCtx<R>, ev: &SupervisorEvent<R>) -> ActionResult
where
    R: bloxide_core::capability::BloxRuntime,
{
    if let SupervisorEvent::Child(Envelope(_, ChildLifecycleEvent::Reset { child_id })) = ev {
        let from = ctx.self_id();
        ctx.children_mut().handle_reset(*child_id, from);
    }
    ActionResult::Ok
}

