/// Register a new static child.
pub fn register_child<R>(ctx: &mut SupervisorCtx<R>, ev: &SupervisorEvent<R>) -> ActionResult
where
    R: bloxide_core::capability::BloxRuntime,
{
    if let SupervisorEvent::Control(Envelope(_, SupervisorControl::RegisterChild(child))) = ev {
        let from = ctx.self_id();
        let (id, lifecycle_ref, policy) = (child.id, child.lifecycle_ref.clone(), child.policy);
        ctx.children_mut().add(id, lifecycle_ref, policy);
        ctx.children_mut().start_child(id, from);
    }
    ActionResult::Ok
}

/// Handle a `RegisterDynamicChild` control message.
///
/// Called when the supervisor receives a `SupervisorControl::RegisterDynamicChild`
/// from the `spawn_child` helper. Registers the child in the child group
/// (storing the `kill_ref` for the kill mailbox and the `abort_handle` for
/// the external abort ripcord) and sends a Start command.
///
/// The `abort_handle` is `Clone` (it's `R::AbortHandle`), so we can clone it
/// from `&Event` — the HSM engine passes `&Event` to action functions, not
/// `&mut Event`. This is the key advantage of `AbortHandle` over `TaskHandle`
/// (`JoinHandle<()>` is not `Clone`).
pub fn handle_register_dynamic_child<R>(
    ctx: &mut SupervisorCtx<R>,
    ev: &SupervisorEvent<R>,
) -> ActionResult
where
    R: bloxide_core::capability::BloxRuntime,
{
    if let SupervisorEvent::Control(Envelope(_, SupervisorControl::RegisterDynamicChild(reg))) = ev
    {
        let from = ctx.self_id();
        let child_id = reg.id;
        ctx.children_mut().add_dynamic(
            child_id,
            reg.lifecycle_ref.clone(),
            reg.kill_ref.clone(),
            reg.abort_handle.clone(),
            reg.policy,
        );
        ctx.children_mut().start_child(child_id, from);
    }
    ActionResult::Ok
}

/// Handle a health-check tick.
pub fn handle_health_check<R>(ctx: &mut SupervisorCtx<R>, ev: &SupervisorEvent<R>) -> ActionResult
where
    R: bloxide_core::capability::BloxRuntime,
{
    if let SupervisorEvent::Control(Envelope(_, SupervisorControl::HealthCheckTick)) = ev {
        let from = ctx.self_id();
        let action = ctx.children_mut().health_check_tick(from);
        ctx.set_pending(action);
    }
    ActionResult::Ok
}
